import { useEffect, useState } from 'react';
import { BrowserRouter as Router } from 'react-router-dom';
import { useDispatch } from 'react-redux';
import Navbar from './components/Navbar/Navbar';
import Allroutes from './Allroutes';
import { fetchMandaps } from './actions/mandaps';
import { fetchNearbyServices } from './actions/services';
import './App.css';

function App() {
  const [userLocation, setUserLocation] = useState(null);
  const [selectedDistance, setSelectedDistance] = useState(5); // Default 5km radius
  const dispatch = useDispatch();

  // Get user location on component mount
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setUserLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude
          });
        },
        (error) => {
          console.error("Error getting location:", error);
        }
      );
    }
  }, []);

  // Fetch mandaps and nearby services when location is available
  useEffect(() => {
    if (userLocation) {
      dispatch(fetchMandaps(userLocation, selectedDistance));
      dispatch(fetchNearbyServices(userLocation, selectedDistance));
    }
  }, [userLocation, selectedDistance, dispatch]);

  return (
    <div className="App">
      <Router>
        <Navbar />
        <Allroutes 
          userLocation={userLocation}
          selectedDistance={selectedDistance}
          setSelectedDistance={setSelectedDistance}
        />
      </Router>
    </div>
  );
}

export default App;
